                   + CASE WHEN 3  =s$mesInicial-1$s AND (PLAN_CONTABLE.NATURALEZA='D' AND SALDO3<0 OR  PLAN_CONTABLE.NATURALEZA='C' AND SALDO3>0)  THEN ABS(PLAN_CONTABLE.SALDO3)  ELSE 0 END
