                   + CASE WHEN 6  =s$mesFinal$s AND (PLAN_CONTABLE.NATURALEZA='D' AND SALDO6<0 OR  PLAN_CONTABLE.NATURALEZA='C' AND SALDO6>0)  THEN ABS(PLAN_CONTABLE.SALDO6)  ELSE 0 END
                   + CASE WHEN 7  =s$mesFinal$s AND (PLAN_CONTABLE.NATURALEZA='D' AND SALDO7<0 OR  PLAN_CONTABLE.NATURALEZA='C' AND SALDO7>0)  THEN ABS(PLAN_CONTABLE.SALDO7)  ELSE 0 END
