                   + CASE WHEN 9  =s$mesFinal$s AND (PLAN_CONTABLE.NATURALEZA='D' AND SALDO9<0 OR  PLAN_CONTABLE.NATURALEZA='C' AND SALDO9>0)  THEN ABS(PLAN_CONTABLE.SALDO9)  ELSE 0 END
