                   + CASE WHEN 11 =s$mesFinal$s AND (PLAN_CONTABLE.NATURALEZA='D' AND SALDO11<0 OR  PLAN_CONTABLE.NATURALEZA='C' AND SALDO11>0)  THEN ABS(PLAN_CONTABLE.]') || TO_CLOB(q'[SALDO11) ELSE 0 END
                   + CASE WHEN 12 =s$mesFinal$s AND (PLAN_CONTABLE.NATURALEZA='D' AND SALDO12<0 OR  PLAN_CONTABLE.NATURALEZA='C' AND SALDO12>0)  THEN ABS(PLAN_CONTABLE.SALDO12) ELSE 0 END
                   + CASE WHEN 13 =s$mesFinal$s AND (PLAN_CONTABLE.NATURALEZA='D' AND SALDO13<0 OR  PLAN_CONTABLE.NATURALEZA='C' AND SALDO13>0)  THEN ABS(PLAN_CONTABLE.SALDO13) ELSE 0 END
                   ) SALDOFINCRE                                                                             

           FROM  PLAN_CONTABLE
